import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: base premiums, empty list, processing fee ---
  it.todo("empty items list with 0-year customer yields premium 5 (only processing fee)");
  it.todo("single amulet (0 years) yields premium 71 (60 base * 1.10 first-ins + 5 fee)");
  it.todo("single staff (0 years) yields premium 93 (80 base * 1.10 + 5)");
  it.todo("single potion (0 years) yields premium 49 (40 base * 1.10 + 5)");
  it.todo("single sword (0 years) yields premium 115 (100 base * 1.10 + 5)");
  it.todo("single rune (0 years) yields premium 33 (25 * 1.10 = 27.5 rounded up to 28, + 5)");

  // --- Quote: component building blocks (R2) ---
  it.todo("2 runes (no block) yields base 50, premium 60 (50 * 1.10 = 55, + 5)");
  it.todo("3 runes (block applies) yields base 60, premium 71 (60 * 1.10 = 66, + 5)");
  it.todo("4 runes (no block, block requires exactly 3) yields base 100, premium 115");
  it.todo("7 runes (no block) yields base 175, premium 198 (175 * 1.10 = 192.5 rounded up to 193, + 5)");

  // --- Quote: alike means same type (Q1) ---
  it.todo("2 runes + 1 moonstone yields base 75 (no block: different types), premium 88 (75*1.10=82.5→83, +5)");
  it.todo("3 runes + 3 moonstones yields base 120 (two separate blocks), premium 137 (120*1.10=132, +5)");

  // --- Quote: item-level modifiers (R3) ---
  it.todo("cursed sword (steel, ench 3), 0 years, first quote → premium 165 (integration example 1: 100 + 50 curse + 10 first-ins + 5 fee)");
  it.todo("sword enchantment exactly 5, 0 years → premium 145 (100 + 30 high-ench + 10 first-ins + 5 = 145)");
  it.todo("sword enchantment 4, 0 years → premium 115 (no high-ench surcharge)");
  it.todo("cursed sword enchantment 5, 0 years → premium 195 (100 + 50 + 30 + 10 + 5)");

  // --- Quote: policy-level modifiers (R4) ---
  it.todo("single sword, customer with exactly 2 years (loyalty applies) → premium 95 (100 + 10 first-ins − 20 loyalty + 5)");
  it.todo("long-standing customer (3 years), second quote in scenario, cursed sword ench 7 → premium 160 (integration example 2)");

  // --- Quote: modifier scope on multi-item policies (R3 vs R4) ---
  it.todo("cursed sword + plain amulet (0 years, first quote) → premium 231 (sword 100*1.6=160, amulet 60*1.1=66, first-ins per item already in; total 226, +5 fee = 231)");

  // --- Quote: rounding in MHPCO's favor (R6) ---
  it.todo("premium calculation yielding 197.5 rounds UP to 198 (e.g., 7 runes case)");

  // --- Claim: standard reimbursement (R8, R9) ---
  it.todo("sword policy (insurance 1000, cap 2000), 500 G damage on regular steel sword (ench 3) → payout 400, remainingCap 1600");
  it.todo("rune policy (insurance 250, cap 500), 200 G damage on rune (no enchantment/material) → payout 100, remainingCap 400");

  // --- Claim: multi-item deductible per damage entry (R8) ---
  it.todo("sword + amulet policy, dragon damages sword 500 and amulet 300 → payout 600 (400+200, each minus own deductible), remainingCap 2600");

  // --- Claim: enchantment threshold vs dragon material (R9) ---
  it.todo("dragon-material sword, enchantment exactly 8, dmg 1000 G → payout 400 (50% high-ench wins, then deductible)");
  it.todo("dragon-material sword, enchantment 9, dmg 1000 G → payout 400 (both apply; 50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, dmg 800 G → payout 700 (only dragon clause: full minus deductible)");
  it.todo("steel sword, enchantment 9, dmg 1000 G → payout 400 (only high-enchantment clause: 50% then deductible)");

  // --- Claim: payout rounding DOWN (R6) ---
  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 (e.g., dragon sword ench 8, dmg 901 → 901/2 − 100 = 350.5 → 350)");

  // --- Claim: multiple items of same type (Q2) ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("two swords insured, dragon damages both swords (500 each) → payout 800 (each with own deductible), remainingCap 3200");

  // --- Claim: cap derivation (R7) ---
  it.todo("cursed sword policy (premium with mods 165 G) → cap 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
  it.todo("sword + 3 runes policy (block discount on premium) → insurance sum 1750 G (= 1000 + 3*250), cap 3500 G (block does not reduce insurance sum)");

  // --- Claim: cap exhaustion across successive claims (R10) ---
  it.todo("sword policy (cap 2000), two successive 1500 G claims: first → payout 1400 remaining 600; second → payout 600 (reduced from 1400 to cap) remaining 0");

  // --- CLI scenario interface (multi-step, policy by index) ---
  it.todo("scenario with quote step 0 then claim referencing policy 0 → results array matches steps order and length");

  // --- Error cases (CLI exits non-zero, stderr, no results stdout) ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, writes error to stderr, no results written to stdout");
  it.todo("claim damage referring to item type not insured in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero, writes error to stderr");
  it.todo("claim damage with unknown item type → CLI exits non-zero, writes error to stderr");
  it.todo("claim damages array has more entries of a type than policy covers (e.g. two sword damages when only one sword insured) → CLI exits non-zero, writes error to stderr, whole claim rejected");
  it.todo("claim damage with negative amount (e.g. amount: -200) → CLI exits non-zero, writes error to stderr");
});
